#include <omp.h>
#include <math.h> // For exp
#include "../main.h"
#include "../util/timer/timer.h"

// Define DOT macro locally if not globally available or ensure it's included
#ifndef DOT
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))
#endif

void kernel_cpu(par_str par_cpu,
                dim_str dim_cpu,
                box_str* box_cpu,
                FOUR_VECTOR* rv_cpu,
                fp* qv_cpu,
                FOUR_VECTOR* fv_cpu)
{
    // Parameters
    fp a2 = 2.0 * par_cpu.alpha * par_cpu.alpha;

    // Loop over all boxes
    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < dim_cpu.number_boxes; ++bx) {
        // Home box parameters
        int first_i = box_cpu[bx].offset;
        FOUR_VECTOR* rA = &rv_cpu[first_i];
        FOUR_VECTOR* fA = &fv_cpu[first_i];

        // Loop over neighbor boxes
        for (int k = 0; k <= box_cpu[bx].nn; ++k) {
            int pointer;
            if (k == 0) {
                pointer = bx; // Home box
            } else {
                pointer = box_cpu[bx].nei[k - 1].number; // Neighbor box
            }

            // Neighbor box parameters
            int first_j = box_cpu[pointer].offset;
            FOUR_VECTOR* rB = &rv_cpu[first_j];
            fp* qB = &qv_cpu[first_j];

            // Loop over particles in the home box
            for (int i = 0; i < NUMBER_PAR_PER_BOX; ++i) {
                // Loop over particles in the neighbor box
                for (int j = 0; j < NUMBER_PAR_PER_BOX; ++j) {
                    fp r2;
                    fp u2;
                    fp vij;
                    fp fs;
                    fp fxij, fyij, fzij;
                    THREE_VECTOR d;

                    // Calculate distance and potential
                    r2 = (fp)rA[i].v + (fp)rB[j].v - DOT(rA[i], rB[j]);
                    u2 = a2 * r2;
                    vij = exp(-u2);
                    fs = 2.0 * vij;

                    // Calculate force components
                    d.x = (fp)rA[i].x - (fp)rB[j].x;
                    fxij = fs * d.x;
                    d.y = (fp)rA[i].y - (fp)rB[j].y;
                    fyij = fs * d.y;
                    d.z = (fp)rA[i].z - (fp)rB[j].z;
                    fzij = fs * d.z;

                    // Accumulate forces
                    fA[i].v += (double)((fp)qB[j] * vij);
                    fA[i].x += (double)((fp)qB[j] * fxij);
                    fA[i].y += (double)((fp)qB[j] * fyij);
                    fA[i].z += (double)((fp)qB[j] * fzij);
                }
            }
        }
    }
}
